(function(){'use strict';const STORAGE_KEY='optima_sidebar_scroll_position';function saveSidebarScrollPosition(){const sidebar=document.querySelector('.sidebar-nav');if(sidebar){sessionStorage.setItem(STORAGE_KEY,sidebar.scrollTop.toString());console.log('Sidebar scroll position saved:',sidebar.scrollTop)}}function restoreSidebarScrollPosition(){const sidebar=document.querySelector('.sidebar-nav');const savedPosition=sessionStorage.getItem(STORAGE_KEY);if(sidebar&&savedPosition !==null){const position=parseInt(savedPosition);sidebar.scrollTop=position;console.log('Sidebar scroll position restored:',position)}}function attachScrollSaveListeners(){document.addEventListener('click',function(e){const navLink=e.target.closest('.sidebar-nav .nav-link');if(navLink){const href=navLink.getAttribute('href');if(href&&!href.startsWith('#')&&!navLink.hasAttribute('data-bs-toggle')&&!e.defaultPrevented){saveSidebarScrollPosition();console.log('Navigation detected,saving scroll position for:',href)}}})}function initializeSidebarScroll(){restoreSidebarScrollPosition();attachScrollSaveListeners();window.addEventListener('beforeunload',saveSidebarScrollPosition);console.log('Sidebar scroll management initialized')}if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',initializeSidebarScroll)}else{initializeSidebarScroll()}window.OptimaSidebar={save:saveSidebarScrollPosition,restore:restoreSidebarScrollPosition,getPosition:function(){const sidebar=document.querySelector('.sidebar-nav');return sidebar ? sidebar.scrollTop:null},setPosition:function(position){const sidebar=document.querySelector('.sidebar-nav');if(sidebar){sidebar.scrollTop=position}}}})();